('HerbSaver UV — UV-suojattu Säilytyspurkki', 'UV-suojattu lasipurkki joka pitää yrtit tuoreina ja potentteina. Ilmatiivis tiiviste, sisäänrakennettu kosteusmittari. Kolme kokoa: S (5g), M (10g), L (30g).', 24.99, 'Vaporisaattorit', 'https://images.unsplash.com/photo-1615486511484-92e172cc4fe0?w=600', TRUE, 89, ARRAY['säilytys','uv-suoja','ilmatiivis','kosteusmittari']),
('CleanKit Pro — Puhdistussetti Höyrystimille', 'Täydellinen puhdistussetti: isopropyylialkoholipyyhkeitä, piippurasseja, puikkoja, pinsetit ja puhdistusharja. Säilytyskotelossa. "Puhdas höyrystin on iloinen höyrystin."', 19.99, 'Vaporisaattorit', 'https://images.unsplash.com/photo-1585435557343-3b092031a831?w=600', TRUE, 120, ARRAY['puhdistus','setti','huolto','tarvikkeet']),

-- Lasitaide & Säilytys (5)
('Rainbow Bowl — Käsinpuhallettu Lasikulho', 'Taiteilijan käsinpuhaltama lasikulho sateenkaaren väreissä. Jokainen kappale uniikki. Pakkauksessa mukana pehmustettu säilytyskotelo. Sopii myös hedelmäkulhoksi.', 59.99, 'Lasitaide', 'https://images.unsplash.com/photo-1576020798425-49a0ba4a0d7a?w=600', TRUE, 8, ARRAY['lasitaide','käsintehty','uniikki','värikäs']),
('Crystal Clear — Kristallinen Bongi', 'Tyylikäs minimalistinen bongi borosilikaattilasista. Helppo puhdistaa, irrotettava alaosa. Korkeus 30cm. Sisältää 14mm kukka-kupin.', 79.99, 'Lasitaide', 'https://images.unsplash.com/photo-1559732277-314a03f52b4f?w=600', TRUE, 15, ARRAY['bongi','kristalli','borosilikaatti','minimalistinen']),
('StashBox Large — Lukollinen Säilytyslaatikko', 'Tyylikäs bambuinen säilytyslaatikko numerolukolla. Sisältää lokerot yrteille, papereille, myllylle ja muille tarvikkeille. Hajuamaton — kämppis ei huomaa.', 44.99, 'Lasitaide', 'https://images.unsplash.com/photo-1602872030219-ad2b9a54315c?w=600', TRUE, 42, ARRAY['säilytys','lukollinen','bambu','hajuton']),
('PipeArt Collection — Koristeellinen Piippu', 'Käsinveistetty puupiippu monimutkaisilla kaiverruksilla. Tammipuuta, käsitelty mehiläisvahalla. Keräilykappale joka on myös toimiva.', 34.99, 'Lasitaide', 'https://images.unsplash.com/photo-1494389360671-0d6b4c3e8e4e?w=600', FALSE, 0, ARRAY['piippu','käsityö','puu','keräily']),
('SmellProof Bag XL — Hajutiivis Laukku', 'Aktiivihiilisuodattimella varustettu hajutiivis kantolaukku. Mahtuu kannettava höyrystin, mylly, purkki ja muut tarvikkeet. Ulospäin näyttää tavalliselta toilettilaukulta.', 29.99, 'Lasitaide', 'https://images.unsplash.com/photo-1544816155-12df9643f363?w=600', TRUE, 55, ARRAY['hajuton','laukku','aktiivihiili','kantolaukku']),

